class LibraryItem:
    def __init__(self, title, author, item_id):
        self.title = title                    # Public attribute for item title
        self.author = author                  # Public attribute for item author
        self.__item_id = item_id              # Private attribute for unique item ID

    def display_info(self):
        print(f"Title: {self.title}")
        print(f"Author: {self.author}")
        print(f"Item ID: {self.__item_id}")

class Book(LibraryItem):
    def __init__(self, title, author, item_id, genre):
        super().__init__(title, author, item_id)  # Call to superclass constructor
        self.genre = genre                       # Additional attribute for book genre

    def display_info(self):
        super().display_info()                   # Call to display_info method from LibraryItem class
        print(f"Genre: {self.genre}")

class Magazine(LibraryItem):
    def __init__(self, title, author, item_id, issue_number):
        super().__init__(title, author, item_id)  # Call to superclass constructor
        self.issue_number = issue_number          # Additional attribute for magazine issue number

    def display_info(self):
        super().display_info()                   # Call to display_info method from LibraryItem class
        print(f"Issue Number: {self.issue_number}")

class Order:
    def __init__(self, borrower_name, borrow_date):
        self.items_in_cart = []                  # List to store items in cart
        self.borrower_name = borrower_name       # Borrower's name
        self.borrow_date = borrow_date           # Date of borrowing

    def add_item(self, item, quantity):
        self.items_in_cart.append((item, quantity))   # Add item and quantity to cart

    def display_order_details(self):
        print(f"Order Details (Borrower: {self.borrower_name}, Borrow Date: {self.borrow_date})")
        for item, quantity in self.items_in_cart:
            item.display_info()
            print("Quantity: {}".format(quantity))

    def display_total_items(self):
        total_items = sum(quantity for _, quantity in self.items_in_cart)  # Calculate total items borrowed
        print("Total Items Borrowed: {}".format(total_items))

