def default_test():
    book = Book("The Great Gatsby", "F. Scott Fitzgerald", "001", "Fiction")
    magazine = Magazine("National Geographic", "Various", "002", 2023)

    order = Order("John Doe", "2024-01-01")
    order.add_item(book, 1)
    order.add_item(magazine, 2)

    order.display_order_details()
